head.script:
(function(){
	'use strict';

	var NOTICE_SEL  = 'script[src*="consent.truste.com/notice"],script[src*="consent.trustarc.com/notice"]';
	var CONSENT_RE  = /(notice_preferences|notice_gdpr_prefs|cmapi_cookie_privacy|consentUUID|truste\.consent)=/i;

	function hasConsent(){ return CONSENT_RE.test(document.cookie); }
	function removeNoticeScripts(){ document.querySelectorAll(NOTICE_SEL).forEach(function(n){ try{ n.remove(); }catch(e){} }); }
	function appendScriptNode(node) {
		var parent = document.head || document.body || document.documentElement;
		parent.appendChild(node);
	}
	function styledPresent(){
		var el = document.getElementById('truste-consent-track');
		if (!el) return false;
		var cs = window.getComputedStyle(el);
		var hasButtons = !!document.getElementById('truste-consent-buttons') || !!document.getElementById('truste-consent-button');
		return (cs.position === 'fixed' || cs.position === 'sticky') && hasButtons;
	}
	function hideBannerNow(){
		var b = document.getElementById('truste-consent-track');
		if (b && b.parentNode) { try { b.parentNode.removeChild(b); } catch(e){} }
		removeNoticeScripts();
	}
	function loadNotice(url, cb){
		var s = document.createElement('script');
		s.async = true; s.crossOrigin = ''; s.src = url;
		s.onload  = function(){ setTimeout(function(){ cb && cb(null); }, 700); };
		s.onerror = function(){ cb && cb(new Error('load failed')); };
		appendScriptNode(s);
	}

	var query   = "domain=us-capgemini.com&c=teconsent&js=bb&noticeType=bb&language=en&cookieLink=https%3A%2F%2Fwww.capgemini.com%2Fus-en%2Fcookie-policy&privacypolicylink=https%3A%2F%2Fwww.capgemini.com%2Fus-en%2Fprivacy-notice&country=us";
	var hosts   = ["consent.trustarc.com","consent.truste.com"];
	var domains = ["us-capgemini.com","mx-capgemini.com"];

	(function(){
		function hasReal() {
			return !!(window.truste && window.truste.eu && typeof window.truste.eu.clickListener === 'function' && !window.truste.eu.clickListener.__shim);
		}
		function loadTA(cb){
			var src = '//' + 'consent.trustarc.com' + '/notice?' + query;
			document.querySelectorAll('script[src*="consent.trustarc.com/notice"],script[src*="consent.truste.com/notice"]').forEach(function(n){ try{ n.remove(); }catch(e){} });
			var s = document.createElement('script');
			s.async = true; s.crossOrigin = ''; s.src = src;
			s.onload = function(){ setTimeout(function(){ cb && cb(); }, 300); };
			appendScriptNode(s);
		}

		function openPrefs(){
			if (hasReal()) { try { window.truste.eu.clickListener(); } catch(e){} return; }
			loadTA(function(){ if (hasReal()) { try { window.truste.eu.clickListener(); } catch(e){} } });
		}
		if (!window.truste) window.truste = {};
		if (!window.truste.eu) window.truste.eu = {};
		if (!hasReal()){
			var shim = function(){ openPrefs(); };
			shim.__shim = true;
			window.truste.eu.clickListener = shim;
			window.taOpenCookiePreferences = openPrefs;
		}
	})();

	// Inject if banner not there yet and no consent yet
	if (!hasConsent()){
		removeNoticeScripts();

		(function tryNext(i, j){
			if (i >= hosts.length) return;
			if (j >= domains.length) return tryNext(i+1, 0);

			var u = '//' + hosts[i] + '/notice?' + query.replace(/(^|&)domain=[^&]*/,'$1domain=' + encodeURIComponent(domains[j]));
			removeNoticeScripts();
			loadNotice(u, function(){
				if (styledPresent() || hasConsent()) return;
				tryNext(i, j+1);
			});
		})(0,0);
	} else {
		hideBannerNow();
	}

	// Hide the banner after consent is given (ASAP)
	document.addEventListener('click', function(ev){
		var id = (ev.target && ev.target.id) || '';
		if (/^(truste\-consent\-button|truste\-consent\-required|truste\-accept|truste\-reject|truste\-show\-consent)$/i.test(id)) {
			var t0 = Date.now();
			var iv = setInterval(function(){
				if (hasConsent()){ clearInterval(iv); hideBannerNow(); }
				else if (Date.now() - t0 > 5000){ clearInterval(iv); }
			}, 100);
		}
	}, true);

	// Defensive repair while banner should be visible
	var repaired = false;
	var mo = new MutationObserver(function(){
		if (hasConsent()){
			try { mo.disconnect(); } catch(e){}
			hideBannerNow();
			return;
		}
		if (!repaired && !styledPresent()){
			repaired = true;
			removeNoticeScripts();
			var first = '//' + hosts[0] + '/notice?' + query.replace(/(^|&)domain=[^&]*/,'$1domain=' + encodeURIComponent(domains[0]));
			loadNotice(first);
		}
	});
	try { mo.observe(document.documentElement, {childList:true, subtree:true}); } catch(e){}
	setTimeout(function(){ if (hasConsent()){ try{mo.disconnect();}catch(e){} hideBannerNow(); } }, 1200);

	// Preference Manager (PM) URL tweaks ONLY (no CSS inside iframe)
	var FORCE_TEST_PM    = false;
	var APPEND_MODE_DARK = true;
	var PM_SITE_TEST     = 'test.cm-capgemini.com';

	function isDarkModeOn(){
		if (!APPEND_MODE_DARK) return false;
		if (document.documentElement.getAttribute('data-theme') === 'dark') return true;
		try {
			var p = new URLSearchParams(location.search);
			return (p.get('mode') || '').toLowerCase() === 'dark';
		} catch(e){ return false; }
	}
	function patchPMIframe(node){
		if (!node || node.tagName !== 'IFRAME') return;
		if (!/truste_popframe/i.test(node.className)) return;
		if (node.dataset.taPatched === '1') return;
		try {
			var u = new URL(node.src, location.href), qs = u.searchParams, changed = false;
			if (FORCE_TEST_PM && qs.get('site') !== PM_SITE_TEST){ qs.set('site', PM_SITE_TEST); changed = true; }
			if (isDarkModeOn() && qs.get('mode') !== 'dark'){ qs.set('mode','dark'); changed = true; }
			if (changed){ node.dataset.taPatched = '1'; node.src = u.toString(); } else { node.dataset.taPatched = '1'; }
		} catch(e){}
	}
	function scanPM(root){ (root||document).querySelectorAll('iframe.truste_popframe').forEach(patchPMIframe); }

	var pmMO = new MutationObserver(function(muts){
		for (var i=0;i<muts.length;i++){
			var m = muts[i];
			for (var j=0;j<m.addedNodes.length;j++){
				var n = m.addedNodes[j];
				if (n && n.nodeType === 1){
					if (n.tagName === 'IFRAME') patchPMIframe(n);
					scanPM(n);
				}
			}
		}
	});
	try { pmMO.observe(document.documentElement, {childList:true, subtree:true}); } catch(e){}
	setTimeout(function(){ scanPM(document); }, 600);
})();

piAId = '96412';
piCId = '5239';
piHostname = 'pi.pardot.com';

(function() {
    function async_load() {
        var s = document.createElement('script');
        s.type = 'text/javascript';
        s.src = ('https:' == document.location.protocol ? 'https://pi' : 'http://cdn') + '.pardot.com/pd.js';
        var c = document.getElementsByTagName('script')[0];
        c.parentNode.insertBefore(s, c);
    }
    if(window.attachEvent) {
        window.attachEvent('onload', async_load);
    } else {
        window.addEventListener('load', async_load, false);
    }
})();

