body.script:
		var entityMap = {
			'&': '&',
			'<': '<',
			'>': '>',
			'"': '"',
			"'": "'",
			'/': '/',
			'`': '`',
			'=': '='
		};

		function escapeHtmlHeader(string) {
			return String(string).replace(/[&<>"'`=\/]/g, function(s) {
				return entityMap[s];
			});
		}
		var noresult = '
No results found';

		function fetch_search_result() {
			let paged = 1;
			if (escapeHtmlHeader(jQuery('#searchform input:text').val())) {
				jQuery('#searchform input:text').val(escapeHtmlHeader(jQuery('#searchform input:text').val()));
				jQuery.ajax({
					url: 'https://www.capgemini.com/us-en/wp-json/wp/v2/search?allow_search_function',
					type: 'GET',
					data: {
						search: escapeHtmlHeader(jQuery('#searchform input:text').val()),
						paged: paged,
						postperpage: 6
					},
					success: function(success) {
						var html = "";
						if (success.length > 0) {
							success.forEach((data, index) => {
								if (index < 5) {
									var dateHtml = "";
									if (data.type !== "post" && data.type !== "page") {
										dateHtml = '' + data.formatted_date + '';
									}
									html += '
' + data.post_type_name + '
' + data.title + '' + dateHtml + '';
								}
							});
						} else {
							html += '
' + noresult + '';
						}
						jQuery('#search_result').html(html);
					},
					error: function(error) {
						jQuery('#search_result').html("No results found");
					}
				});
			}

		}

	( function() {
		var skipLinkTarget = document.querySelector( 'main' ),
			sibling,
			skipLinkTargetID,
			skipLink;

		// Early exit if a skip-link target can't be located.
		if ( ! skipLinkTarget ) {
			return;
		}

		/*
		 * Get the site wrapper.
		 * The skip-link will be injected in the beginning of it.
		 */
		sibling = document.querySelector( '.wp-site-blocks' );

		// Early exit if the root element was not found.
		if ( ! sibling ) {
			return;
		}

		// Get the skip-link target's ID, and generate one if it doesn't exist.
		skipLinkTargetID = skipLinkTarget.id;
		if ( ! skipLinkTargetID ) {
			skipLinkTargetID = 'wp--skip-link--target';
			skipLinkTarget.id = skipLinkTargetID;
		}

		// Create the skip link.
		skipLink = document.createElement( 'a' );
		skipLink.classList.add( 'skip-link', 'screen-reader-text' );
		skipLink.id = 'wp-skip-link';
		skipLink.href = '#' + skipLinkTargetID;
		skipLink.innerText = 'Skip to content';

		// Inject the skip link.
		sibling.parentElement.insertBefore( skipLink, sibling );
	}() );

//# sourceURL=wp-block-template-skip-link-js-after

